	"encoding/hex"
	"fmt"
)

func main() {
	key := []byte{0x0b, 0x0b, 0x0b, 0x0b, 0x0b, 0x0b, 0x0b, 0x0b, 0x0b, 0x0b, 0x0b, 0x0b, 0x0b, 0x0b, 0x0b, 0x0b, 0x0b, 0x0b, 0x0b, 0x0b}
	mac := hmac.New(sha256.New, key)
	_, _ = mac.Write([]byte("Hi There"))
	got := hex.EncodeToString(mac.Sum(nil))
	want := "b0344c61d8db38535ca8afceaf0bf12b881dc200c9833da726e9376c2e32cff7"
	fmt.Printf("rfc_vector=%t changed_case=4 negative_vectors_required=true\n", got == want)
}
